I'm happy to help! Here is an example of a simple C++ program that calculates the Fibonacci sequence up to 100:
```cpp
#include <iostream>
using namespace std;

int fibonacci(int n) {
    if (n <= 1)
        return n;
    else
        return fibonacci(n - 1) + fibonacci(n - 2);
}

int main() {
    int n = 100;
    cout << "Fibonacci sequence up to " << n << " terms:" << endl;
    for (int i = 0; i <= n; ++i) {
        cout << fibonacci(i) << ' ';
    }
    return 0;
}
```
This program uses recursion to calculate the Fibonacci sequence and prints it up to the specified number (in this case, 100).

Yes, I can help you modify the C++ program to take `n` as a command line argument for a more flexible input:
```cpp
#include <iostream>
#include <cstdlib> // For atoi() function
using namespace std;

int fibonacci(int n) {
    if (n <= 1)
        return n;
    else
        return fibonacci(n - 1) + fibonacci(n - 2);
}

int main(int argc, char* argv[]) {
    int n = atoi(argv[1]); // Convert command line argument to integer
    cout << "Fibonacci sequence up to " << n << " terms:" << endl;
    for (int i = 0; i <= n; ++i) {
        cout << fibonacci(i) << ' ';
    }
    return 0;
}
```
